import cron from 'node-cron';
import { fetchAllApiJobs } from '../scrapers/apiScrapers.js';
import { fetchAllRssJobs } from '../scrapers/rssScrapers.js';
import { runAllWebScrapers } from '../scrapers/webScrapers.js';
import { normalizeJobData, deduplicateJobs } from '../pipeline/normalizer.js';
import { PrismaClient } from '@prisma/client';

const prisma = new PrismaClient();

export async function runScoringPipeline() {
    console.log(`[${new Date().toISOString()}] Starting Data Pipeline...`);
    try {
        const apiJobs = await fetchAllApiJobs();
        const rssJobs = await fetchAllRssJobs();
        const webJobs = await runAllWebScrapers();

        const allJobs = [...apiJobs, ...rssJobs, ...webJobs];
        console.log(`Fetched ${allJobs.length} raw jobs`);

        const normalized = normalizeJobData(allJobs);
        const deduped = deduplicateJobs(normalized);
        console.log(`After normalization and dedup: ${deduped.length} distinct jobs`);

        // Attempt inserting into DB
        let newJobsCount = 0;
        for (const job of deduped) {
            try {
                await prisma.job.upsert({
                    where: { url: job.url },
                    update: {
                        fetchTime: new Date()
                    },
                    create: job
                });
                newJobsCount++;
            } catch (e) { /* ignore constraint errs etc */ }
        }

        console.log(`[${new Date().toISOString()}] Data Pipeline finished. Inserted/Updated ${newJobsCount} jobs.`);

        await prisma.scraperLog.create({
            data: {
                source: 'Cron Pipeline',
                status: 'SUCCESS',
                jobsAdded: newJobsCount
            }
        });

    } catch (error) {
        console.error('Data pipeline error:', error);
        await prisma.scraperLog.create({
            data: {
                source: 'Cron Pipeline',
                status: 'ERROR',
                errors: error.message
            }
        });
    }
}

// Run every 6 hours
export function startCron() {
    console.log('Starting node-cron scheduler (every 6 hours)');
    cron.schedule('0 */6 * * *', () => {
        runScoringPipeline();
    });
}

import express from 'express';
import cors from 'cors';
import dotenv from 'dotenv';
import { PrismaClient } from '@prisma/client';
import { runScoringPipeline, startCron } from './cron/scheduler.js';
import { scoreJobMatch } from './engine/atsMatcher.js';
import { scrapeLinkedInRecruiters, findEmail } from './scrapers/hrScraper.js';

dotenv.config();

const app = express();
const PORT = process.env.PORT || 5000;
const prisma = new PrismaClient();

app.use(cors());
app.use(express.json());

// Start the 6-hour cron
startCron();

// API ROUTES

app.get('/api/health', (req, res) => {
    res.json({ status: 'ok', message: 'Job Portal API is running' });
});

// Get all jobs, with optional matching based on user profile
app.post('/api/jobs', async (req, res) => {
    try {
        const { userProfile, category, location } = req.body;

        // Build where clause
        const where = {};
        if (category && category !== 'All Roles') where.category = { contains: category, mode: 'insensitive' };
        if (location && location !== 'All India') where.location = { contains: location, mode: 'insensitive' };

        const jobs = await prisma.job.findMany({
            where,
            orderBy: { postedAt: 'desc' },
            take: 100
        });

        if (userProfile && Object.keys(userProfile).length > 0) {
            // Apply ATS matching
            const scoredJobs = jobs.map(job => {
                const matchResult = scoreJobMatch(userProfile, job);
                return { ...job, atsScore: matchResult.matchScore, atsReport: matchResult.report };
            });
            // Sort by score
            scoredJobs.sort((a, b) => b.atsScore - a.atsScore);
            return res.json(scoredJobs);
        }

        res.json(jobs);
    } catch (error) {
        res.status(500).json({ error: error.message });
    }
});

// Trigger manual scraper run (for Admin Panel)
app.post('/api/admin/scrape', async (req, res) => {
    try {
        // Run async to not block
        runScoringPipeline();
        res.json({ message: 'Scraping pipeline started' });
    } catch (error) {
        res.status(500).json({ error: error.message });
    }
});

// Get Scraper Logs
app.get('/api/admin/logs', async (req, res) => {
    try {
        const logs = await prisma.scraperLog.findMany({
            orderBy: { runTime: 'desc' },
            take: 50
        });
        res.json(logs);
    } catch (error) {
        res.status(500).json({ error: error.message });
    }
});

// Fetch HR Contacts
app.get('/api/hr', async (req, res) => {
    try {
        const contacts = await prisma.hRContact.findMany({
            orderBy: { lastUpdated: 'desc' }
        });
        res.json(contacts);
    } catch (error) {
        res.status(500).json({ error: error.message });
    }
});

// Trigger HR Scraper for a specific company
app.post('/api/hr/scrape', async (req, res) => {
    try {
        const { companyName } = req.body;
        if (!companyName) return res.status(400).json({ error: 'Company name required' });

        const profiles = await scrapeLinkedInRecruiters(companyName);

        let addedCount = 0;
        for (const p of profiles) {
            // Find email
            const domain = companyName.toLowerCase().replace(/[^a-z0-9]/g, '') + '.com'; // basic guess
            const email = await findEmail(domain, p.name.split(' ')[0], p.name.split(' ')[1] || '');

            try {
                await prisma.hRContact.upsert({
                    where: { linkedin: p.linkedin },
                    update: { email, lastUpdated: new Date() },
                    create: { ...p, email }
                });
                addedCount++;
            } catch (err) { }
        }

        res.json({ message: `Scraped and added ${addedCount} recruiters for ${companyName}` });
    } catch (error) {
        res.status(500).json({ error: error.message });
    }
});

app.listen(PORT, () => {
    console.log(`Server is running on port ${PORT}`);
});

import axios from 'axios';

// Unified API scrapers for free APIs
export async function fetchRemotiveJobs() {
    try {
        const response = await axios.get('https://remotive.com/api/remote-jobs?category=software-dev');
        const jobs = response.data.jobs || [];
        return jobs.map(job => ({
            title: job.title,
            company: job.company_name,
            source: 'Remotive',
            category: job.category,
            skills: job.tags || [],
            location: job.candidate_required_location,
            url: job.url,
            description: job.description.substring(0, 500),
            postedAt: new Date(job.publication_date)
        }));
    } catch (error) {
        console.error('Error fetching from Remotive:', error.message);
        return [];
    }
}

export async function fetchAdzunaJobs() {
    const appId = process.env.ADZUNA_APP_ID;
    const appKey = process.env.ADZUNA_APP_KEY;
    if (!appId || !appKey) return [];

    try {
        const response = await axios.get(`https://api.adzuna.com/v1/api/jobs/in/search/1?app_id=${appId}&app_key=${appKey}&results_per_page=50&what="software developer"`);
        const jobs = response.data.results || [];
        return jobs.map(job => ({
            title: job.title,
            company: job.company.display_name,
            source: 'Adzuna',
            category: job.category.label,
            skills: [],
            location: job.location.display_name,
            url: job.redirect_url,
            description: job.description,
            postedAt: new Date(job.created)
        }));
    } catch (error) {
        console.error('Error fetching from Adzuna:', error.message);
        return [];
    }
}

// JSearch (RapidAPI) requires API Key
export async function fetchJSearchJobs() {
    const apiKey = process.env.RAPIDAPI_KEY;
    if (!apiKey) return [];

    try {
        const options = {
            method: 'GET',
            url: 'https://jsearch.p.rapidapi.com/search',
            params: { query: 'software developer in india', page: '1', num_pages: '1' },
            headers: {
                'X-RapidAPI-Key': apiKey,
                'X-RapidAPI-Host': 'jsearch.p.rapidapi.com'
            }
        };
        const response = await axios.request(options);
        const jobs = response.data.data || [];

        return jobs.map(job => ({
            title: job.job_title,
            company: job.employer_name,
            source: 'JSearch',
            category: job.job_job_title,
            skills: job.job_required_skills || [],
            location: job.job_city ? `${job.job_city}, ${job.job_country}` : 'Remote',
            url: job.job_apply_link,
            description: job.job_description.substring(0, 500),
            postedAt: new Date(job.job_posted_at_datetime_utc)
        }));
    } catch (error) {
        console.error('Error fetching from JSearch:', error.message);
        return [];
    }
}

export async function fetchAllApiJobs() {
    console.log('Fetching from Free APIs...');
    const [remotive, adzuna, jsearch] = await Promise.all([
        fetchRemotiveJobs(),
        fetchAdzunaJobs(),
        fetchJSearchJobs()
    ]);

    return [...remotive, ...adzuna, ...jsearch];
}

import puppeteer from 'puppeteer';
import axios from 'axios';

// Generic delay function for rate limiting
const delay = ms => new Promise(res => setTimeout(res, ms));

export async function scrapeLinkedInRecruiters(companyName) {
    let browser;
    try {
        browser = await puppeteer.launch({
            headless: "new",
            args: ['--no-sandbox', '--disable-setuid-sandbox']
        });

        const page = await browser.newPage();
        await page.setUserAgent('Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36');

        // Instead of logging into LinkedIn (which requires auth and risks bans), 
        // a common approach is to search Google for public LinkedIn profiles.
        const query = encodeURIComponent(`site:linkedin.com/in/ "recruiter" OR "talent acquisition" "${companyName}" India`);
        await page.goto(`https://www.google.com/search?q=${query}`, { waitUntil: 'domcontentloaded' });

        await delay(2000); // Rate limit

        const results = await page.evaluate((company) => {
            const links = Array.from(document.querySelectorAll('a'));
            const profiles = [];

            for (const link of links) {
                if (link.href && link.href.includes('linkedin.com/in/')) {
                    const titleEl = link.querySelector('h3');
                    if (titleEl) {
                        const fullTitle = titleEl.innerText;
                        // E.g., "John Doe - Talent Acquisition - Razorpay | LinkedIn"
                        const name = fullTitle.split('-')[0].trim();
                        profiles.push({
                            name: name,
                            linkedin: link.href,
                            company: company,
                            role: 'Recruiter / Talent Acquisition'
                        });
                    }
                }
            }
            return profiles;
        }, companyName);

        // Deduplicate profiles
        const uniqueProfiles = [];
        const seenUrls = new Set();
        for (const p of results) {
            // clean URL from Google tracking params
            let cleanUrl = p.linkedin;
            try {
                const urlObj = new URL(p.linkedin);
                cleanUrl = urlObj.searchParams.get('url') || p.linkedin;
                // Basic cleanup
                cleanUrl = cleanUrl.split('?')[0];
            } catch (e) { }

            if (!seenUrls.has(cleanUrl) && cleanUrl.includes('linkedin.com/in/')) {
                seenUrls.add(cleanUrl);
                uniqueProfiles.push({ ...p, linkedin: cleanUrl });
            }
        }

        return uniqueProfiles.slice(0, 5); // Return top 5

    } catch (error) {
        console.error(`Error scraping recruiters for ${companyName}:`, error.message);
        return [];
    } finally {
        if (browser) await browser.close();
    }
}

// Dummy/Hunter.io integration for finding emails
export async function findEmail(domain, firstName, lastName) {
    // If Hunter API key is provided, use it. Otherwise, return a generic/dummy email.
    const apiKey = process.env.HUNTER_API_KEY;
    if (!apiKey) {
        // Generate a placeholder email
        return `${firstName.toLowerCase()}.${lastName.toLowerCase()}@${domain}`;
    }

    try {
        const response = await axios.get(`https://api.hunter.io/v2/email-finder?domain=${domain}&first_name=${firstName}&last_name=${lastName}&api_key=${apiKey}`);
        if (response.data && response.data.data && response.data.data.email) {
            return response.data.data.email;
        }
    } catch (error) {
        console.error(`Error finding email for ${domain}:`, error.message);
    }
    return null;
}

import * as React from 'react';
import {
  Briefcase, Linkedin, Users, FileText, ClipboardList, User, Bell, Settings, Search, Rocket, Database
} from 'lucide-react';
import { Toast, Button, Avatar } from './components/ui';
import { useLocalStorage } from './hooks/useHooks';
import { MOCK_HRS, USER_PROFILE } from './data/constants';
import JobSearchTab from './components/JobSearchTab';
import LinkedInFinderTab from './components/LinkedInFinderTab';
import HRContactsTab from './components/HRContactsTab';
import ResumeTab from './components/ResumeTab';
import ApplicationsTab from './components/ApplicationsTab';
import MyProfileTab from './components/MyProfileTab';
import AdminPanelTab from './components/AdminPanelTab';

export default function JobHunterPro() {
  const [activeTab, setActiveTab] = React.useState('jobs');
  const [toast, setToast] = React.useState({ show: false, message: '', type: 'success' });
  const showToast = React.useCallback((message, type = 'success') => setToast({ show: true, message, type }), []);

  const [savedJobs, setSavedJobs] = useLocalStorage('jh_saved_jobs', []);
  const [savedNotes, setSavedNotes] = useLocalStorage('jh_resume_notes', []);
  const [hrContacts, setHrContacts] = useLocalStorage('jh_hr_contacts', MOCK_HRS);
  const [apps, setApps] = useLocalStorage('jh_applications', [
    { id: 'app1', title: 'APM Intern', company: 'Razorpay', date: '2026-02-28', status: 'Applied', match: 92 },
    { id: 'app2', title: 'Product Analyst', company: 'Freshworks', date: '2026-02-25', status: 'Interview Scheduled', match: 88 },
  ]);

  const tabs = [
    { id: 'jobs', label: 'Discover', icon: Briefcase },
    { id: 'linkedin', label: 'LinkedIn', icon: Linkedin },
    { id: 'hr', label: 'HR Finder', icon: Users },
    { id: 'admin', label: 'Admin', icon: Database },
    { id: 'resume', label: 'Resume', icon: FileText },
    { id: 'applications', label: 'Tracker', icon: ClipboardList },
    { id: 'profile', label: 'Profile', icon: User },
  ];

  // Force dark mode
  React.useEffect(() => {
    document.documentElement.classList.add('dark');
  }, []);

  return (
    <div className="min-h-screen bg-black selection:bg-blue-500/30">
      {/* Animated Orbs Background */}
      <div className="fixed inset-0 overflow-hidden pointer-events-none z-0">
        <div className="absolute top-0 left-1/4 w-[500px] h-[500px] bg-blue-500/5 rounded-full blur-[120px] animate-pulse" />
        <div className="absolute bottom-0 right-1/4 w-[500px] h-[500px] bg-purple-500/5 rounded-full blur-[120px] animate-pulse" style={{ animationDelay: '1s' }} />
      </div>

      <div className="relative z-10">
        {/* SHADCN STYLE HEADER */}
        <header className="sticky top-0 z-50 backdrop-blur-xl bg-black/60 border-b border-white/10 shadow-lg">
          <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
            <div className="flex items-center justify-between h-16">
              {/* Logo */}
              <div className="flex items-center gap-3 group cursor-pointer" onClick={() => setActiveTab('jobs')}>
                <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-blue-600 to-purple-600 flex items-center justify-center shadow-lg shadow-blue-500/20 group-hover:scale-110 transition-transform duration-300">
                  <Rocket size={20} className="text-white fill-white/10" />
                </div>
                <div className="flex flex-col">
                  <h1 className="text-sm font-bold text-white tracking-wider leading-none">JOBHUNTER</h1>
                  <span className="text-[10px] font-black text-zinc-500 tracking-[0.2em] mt-1">PRO EDITION</span>
                </div>
              </div>

              {/* Navigation Tabs */}
              <nav className="hidden md:flex items-center gap-1 bg-white/5 border border-white/10 p-1 rounded-full">
                {tabs.map(t => {
                  const isActive = activeTab === t.id;
                  return (
                    <button
                      key={t.id}
                      onClick={() => setActiveTab(t.id)}
                      className={`flex items-center gap-2 px-4 py-1.5 rounded-full text-xs font-bold transition-all duration-300 relative
                        ${isActive
                          ? 'text-white bg-white/10 shadow-inner'
                          : 'text-zinc-500 hover:text-zinc-300 hover:bg-white/5'}`}
                    >
                      <t.icon size={14} className={isActive ? "text-blue-400" : ""} />
                      {t.label}
                      {isActive && <div className="absolute bottom-0 left-1/2 -translate-x-1/2 w-1 h-3 bg-blue-500/80 blur-lg rounded-full" />}
                    </button>
                  );
                })}
              </nav>

              {/* User Actions */}
              <div className="flex items-center gap-3">
                <Button variant="ghost" size="icon" className="h-9 w-9 text-zinc-400 hover:text-white sm:flex hidden">
                  <Search size={18} />
                </Button>
                <Button variant="ghost" size="icon" className="h-9 w-9 text-zinc-400 hover:text-white relative">
                  <Bell size={18} />
                  <span className="absolute top-2 right-2 w-2 h-2 bg-red-500 rounded-full border-2 border-black" />
                </Button>
                <div className="h-8 w-px bg-white/10 mx-1 sm:block hidden" />
                <Avatar className="cursor-pointer hover:border-blue-500/50 transition-colors">
                  {USER_PROFILE.name.split(' ').map(n => n[0]).join('')}
                </Avatar>
              </div>
            </div>
          </div>
        </header>

        {/* MOBILE NAVIGATION BAR (Sticky Bottom) */}
        <nav className="md:hidden fixed bottom-6 left-1/2 -translate-x-1/2 z-50 bg-zinc-900/80 backdrop-blur-xl border border-white/10 rounded-full p-1.5 shadow-2xl flex items-center gap-1">
          {tabs.map(t => (
            <button
              key={t.id}
              onClick={() => setActiveTab(t.id)}
              className={`p-3 rounded-full transition-all duration-300
                ${activeTab === t.id ? 'bg-blue-600 text-white' : 'text-zinc-500'}`}
            >
              <t.icon size={20} />
            </button>
          ))}
        </nav>

        {/* MAIN LAYOUT */}
        <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8 pb-24 md:pb-12">
          {activeTab === 'jobs' && <JobSearchTab savedJobs={savedJobs} setSavedJobs={setSavedJobs} showToast={showToast} />}
          {activeTab === 'linkedin' && <LinkedInFinderTab showToast={showToast} />}
          {activeTab === 'hr' && <HRContactsTab showToast={showToast} />}
          {activeTab === 'admin' && <AdminPanelTab showToast={showToast} />}
          {activeTab === 'resume' && <ResumeTab savedNotes={savedNotes} setSavedNotes={setSavedNotes} showToast={showToast} />}
          {activeTab === 'applications' && <ApplicationsTab apps={apps} setApps={setApps} showToast={showToast} />}
          {activeTab === 'profile' && <MyProfileTab />}
        </main>
      </div>

      <Toast {...toast} onClose={() => setToast({ ...toast, show: false })} />
    </div>
  );
}

