import React, { useState, useEffect } from 'react';
import { Play, Database, AlertCircle, CheckCircle2, Clock } from 'lucide-react';
import { Button } from './ui';

export default function AdminPanelTab({ showToast }) {
    const [logs, setLogs] = useState([]);
    const [loading, setLoading] = useState(false);
    const [scraping, setScraping] = useState(false);

    const fetchLogs = async () => {
        setLoading(true);
        try {
            const res = await fetch('/api/admin/logs');
            if (res.ok) {
                const data = await res.json();
                setLogs(data);
            }
        } catch (err) {
            console.error(err);
            showToast('Failed to fetch logs', 'error');
        }
        setLoading(false);
    };

    useEffect(() => {
        fetchLogs();
    }, []);

    const triggerScrape = async () => {
        setScraping(true);
        try {
            const res = await fetch('/api/admin/scrape', { method: 'POST' });
            if (res.ok) {
                showToast('Data pipeline started in the background.', 'success');
                setTimeout(fetchLogs, 5000); // refresh logs after 5s
            }
        } catch (err) {
            showToast('Failed to trigger scraper', 'error');
        }
        setScraping(false);
    };

    return (
        <div className="space-y-6 animate-fade-in fade-in">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                <div>
                    <h2 className="text-2xl font-bold text-white flex items-center gap-2">
                        <Database className="text-blue-400" />
                        Data Operations
                    </h2>
                    <p className="text-zinc-400 mt-1">Monitor scrapers and trigger manual data pipeline runs</p>
                </div>

                <div className="flex gap-3">
                    <Button variant="outline" onClick={fetchLogs} disabled={loading} className="border-white/10 text-white hover:bg-white/5">
                        Refresh Logs
                    </Button>
                    <Button
                        onClick={triggerScrape}
                        disabled={scraping}
                        className="bg-gradient-to-r from-blue-600 to-purple-600 hover:from-blue-500 hover:to-purple-500 text-white border-0 shadow-lg shadow-blue-500/20"
                    >
                        {scraping ? 'Starting...' : <><Play size={16} className="mr-2" /> Run Pipeline</>}
                    </Button>
                </div>
            </div>

            <div className="bg-white/5 border border-white/10 rounded-2xl overflow-hidden p-1">
                <div className="bg-black/40 rounded-xl overflow-x-auto">
                    <table className="w-full text-sm text-left align-middle text-zinc-300">
                        <thead className="text-xs text-zinc-400 uppercase bg-white/5 border-b border-white/10">
                            <tr>
                                <th className="px-6 py-4 font-semibold">Time</th>
                                <th className="px-6 py-4 font-semibold">Source</th>
                                <th className="px-6 py-4 font-semibold">Status</th>
                                <th className="px-6 py-4 font-semibold">Jobs Added</th>
                                <th className="px-6 py-4 font-semibold">Errors</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-white/5">
                            {logs.length === 0 ? (
                                <tr><td colSpan="5" className="px-6 py-8 text-center text-zinc-500">No logs available</td></tr>
                            ) : (
                                logs.map((log) => (
                                    <tr key={log.id} className="hover:bg-white/5 transition-colors group">
                                        <td className="px-6 py-4 flex items-center gap-2">
                                            <Clock size={14} className="text-zinc-500" />
                                            {new Date(log.runTime).toLocaleString()}
                                        </td>
                                        <td className="px-6 py-4 font-medium text-white">{log.source}</td>
                                        <td className="px-6 py-4">
                                            {log.status === 'SUCCESS' ? (
                                                <span className="flex items-center gap-1.5 text-emerald-400 bg-emerald-400/10 px-2 py-0.5 rounded-full w-fit whitespace-nowrap">
                                                    <CheckCircle2 size={14} /> Success
                                                </span>
                                            ) : (
                                                <span className="flex items-center gap-1.5 text-red-400 bg-red-400/10 px-2 py-0.5 rounded-full w-fit whitespace-nowrap">
                                                    <AlertCircle size={14} /> Error
                                                </span>
                                            )}
                                        </td>
                                        <td className="px-6 py-4">{log.jobsAdded}</td>
                                        <td className="px-6 py-4 text-xs text-red-300 max-w-xs truncate">{log.errors || '-'}</td>
                                    </tr>
                                ))
                            )}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );
}

import * as React from 'react';
import {
    Briefcase, Calendar, Award, Clock, Plus, X, Trash2, Filter, ChevronRight
} from 'lucide-react';
import {
    Button, Card, CardHeader, CardTitle, CardDescription, CardContent,
    Badge, Input, Separator, StatItem
} from './ui';

export default function ApplicationsTab({ apps, setApps, showToast }) {
    const [showForm, setShowForm] = React.useState(false);
    const [form, setForm] = React.useState({
        title: '', company: '', date: new Date().toISOString().split('T')[0], status: 'Applied', match: 80
    });

    const stats = [
        { l: 'Total Applied', v: apps.length, i: Briefcase, trend: '+3 this week' },
        { l: 'Interviews', v: apps.filter(a => a.status.includes('Interview')).length, i: Calendar, trend: '2 scheduled' },
        { l: 'Offers', v: apps.filter(a => a.status === 'Offered').length, i: Award, trend: 'Check emails!' },
        { l: 'Pending', v: apps.filter(a => ['Applied', 'Viewed'].includes(a.status)).length, i: Clock, trend: 'Wait for response' },
    ];

    const saveApp = () => {
        if (!form.title || !form.company) return;
        setApps([{ ...form, id: `app-${Date.now()}` }, ...apps]);
        setShowForm(false); showToast('Application tracked!');
        setForm({ title: '', company: '', date: new Date().toISOString().split('T')[0], status: 'Applied', match: 80 });
    };

    return (
        <div className="space-y-8 animate-fade-in">
            {/* Dashboard Stats */}
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
                {stats.map((s, i) => (
                    <StatItem key={i} icon={s.i} label={s.l} value={s.v} trend={s.trend} />
                ))}
            </div>

            <div className="flex items-center justify-between">
                <h2 className="text-xl font-bold text-white flex items-center gap-2">
                    Application History <Badge variant="secondary">{apps.length}</Badge>
                </h2>
                <Button onClick={() => setShowForm(!showForm)} className="bg-white text-black hover:bg-zinc-200">
                    {showForm ? <X size={16} /> : <Plus size={16} />}
                    <span className="hidden sm:inline ml-2">{showForm ? 'Cancel' : 'Add Application'}</span>
                </Button>
            </div>

            {showForm && (
                <Card className="animate-fade-in-up border-blue-500/20 shadow-lg shadow-blue-500/5">
                    <CardHeader>
                        <CardTitle className="text-white">Track New Opportunity</CardTitle>
                        <CardDescription>Keep context of where you applied and when</CardDescription>
                    </CardHeader>
                    <CardContent>
                        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                            <Input placeholder="Job Title *" value={form.title} onChange={e => setForm({ ...form, title: e.target.value })} />
                            <Input placeholder="Company *" value={form.company} onChange={e => setForm({ ...form, company: e.target.value })} />
                            <select
                                value={form.status}
                                onChange={e => setForm({ ...form, status: e.target.value })}
                                className="flex h-10 w-full rounded-md border border-zinc-800 bg-zinc-950 px-3 py-2 text-sm text-zinc-400 outline-none focus:ring-2 focus:ring-zinc-800"
                            >
                                <option value="Applied">Applied</option>
                                <option value="Viewed">Viewed</option>
                                <option value="Interview Scheduled">Interview</option>
                                <option value="Assignment Sent">Assignment</option>
                                <option value="Offered">Offered</option>
                            </select>
                        </div>
                        <div className="mt-6 flex justify-end">
                            <Button onClick={saveApp} variant="apply">Track Now</Button>
                        </div>
                    </CardContent>
                </Card>
            )}

            {/* Applications List */}
            <div className="space-y-3">
                {apps.length === 0 ? (
                    <Card className="p-12 text-center border-dashed border-zinc-800 bg-transparent">
                        <div className="w-12 h-12 rounded-full bg-zinc-900 flex items-center justify-center mx-auto mb-4">
                            <Briefcase size={20} className="text-zinc-600" />
                        </div>
                        <h3 className="text-zinc-400 font-medium">No applications found</h3>
                        <p className="text-xs text-zinc-600 mt-1">Start by applying to some jobs in the Discover tab</p>
                    </Card>
                ) : (
                    apps.map((a, i) => (
                        <Card key={a.id} className="group animate-fade-in-up hover:bg-zinc-900/50 transition-colors border-white/5">
                            <div className="flex items-center justify-between p-4">
                                <div className="flex items-center gap-4">
                                    <div className="w-10 h-10 rounded-lg bg-zinc-900 flex items-center justify-center border border-white/5 font-bold text-zinc-400">
                                        {a.company[0]}
                                    </div>
                                    <div>
                                        <h4 className="text-sm font-bold text-white leading-none">{a.title}</h4>
                                        <p className="text-xs text-zinc-500 mt-1.5 flex items-center gap-2">
                                            {a.company} <span className="text-zinc-700 font-bold">•</span> {new Date(a.date).toLocaleDateString()}
                                        </p>
                                    </div>
                                </div>

                                <div className="flex items-center gap-6">
                                    <div className="hidden md:block">
                                        <p className="text-[10px] font-bold text-zinc-600 uppercase tracking-widest text-right mb-1">ATS Score</p>
                                        <Badge variant="outline" className="font-mono">{a.match}%</Badge>
                                    </div>

                                    <div className="hidden sm:block min-w-[120px]">
                                        <p className="text-[10px] font-bold text-zinc-600 uppercase tracking-widest text-right mb-1">Status</p>
                                        <div className="flex justify-end">
                                            <Badge
                                                className={
                                                    a.status === 'Offered' ? 'bg-emerald-500/10 text-emerald-400 border-emerald-500/20' :
                                                        a.status.includes('Interview') ? 'bg-blue-500/10 text-blue-400 border-blue-500/20' :
                                                            'bg-zinc-800 text-zinc-400'
                                                }
                                            >
                                                {a.status}
                                            </Badge>
                                        </div>
                                    </div>

                                    <div className="flex items-center gap-1">
                                        <Button variant="ghost" size="icon" className="h-8 w-8 text-zinc-600 hover:text-red-500 hover:bg-red-500/5" onClick={() => setApps(apps.filter(x => x.id !== a.id))}>
                                            <Trash2 size={14} />
                                        </Button>
                                        <Button variant="ghost" size="icon" className="h-8 w-8 text-zinc-600">
                                            <ChevronRight size={16} />
                                        </Button>
                                    </div>
                                </div>
                            </div>
                        </Card>
                    ))
                )}
            </div>
        </div>
    );
}

import * as React from 'react';
import {
    Search, Plus, X, Copy, Mail, Linkedin, Building2, Check
} from 'lucide-react';
import {
    Button, Card, CardHeader, CardTitle, CardDescription, CardContent,
    Badge, Input, Avatar, Separator
} from './ui';
import { useDebounce } from '../hooks/useHooks';
import { USER_PROFILE } from '../data/constants';

export default function HRContactsTab({ showToast }) {
    const [hrContacts, setHrContacts] = React.useState([]);
    const [q, setQ] = React.useState('');
    const [showAdd, setShowAdd] = React.useState(false);
    const [form, setForm] = React.useState({
        name: '', company: '', designation: '', email: '', phone: '', linkedinUrl: '', roleHiring: ''
    });
    const [scrapeCompany, setScrapeCompany] = React.useState('');
    const [isScraping, setIsScraping] = React.useState(false);
    const debouncedQ = useDebounce(q);

    const filtered = hrContacts.filter(h => {
        if (debouncedQ && !h.name.toLowerCase().includes(debouncedQ.toLowerCase()) && !h.company.toLowerCase().includes(debouncedQ.toLowerCase())) return false;
        return true;
    });

    const fetchContacts = () => {
        fetch('/api/hr')
            .then(res => res.json())
            .then(data => setHrContacts(data))
            .catch(() => showToast('Failed to fetch HR contacts', 'error'));
    };

    React.useEffect(() => {
        fetchContacts();
    }, []);

    const saveHR = () => {
        if (!form.name || !form.company || !form.email) return;
        setHrContacts([{ ...form, id: `h-${Date.now()}`, isVerified: true, avatarColor: '#3b82f6' }, ...hrContacts]);
        setShowAdd(false); setForm({ name: '', company: '', designation: '', email: '', phone: '', linkedinUrl: '', roleHiring: '' });
        showToast('HR Contact Added!');
    };

    const runScraper = async () => {
        if (!scrapeCompany) return;
        setIsScraping(true);
        try {
            const res = await fetch('/api/hr/scrape', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ companyName: scrapeCompany })
            });
            const data = await res.json();
            showToast(data.message || 'Scraping finished');
            fetchContacts();
        } catch (err) {
            showToast('Scraping failed', 'error');
        }
        setIsScraping(false);
        setScrapeCompany('');
    };

    const copy = (txt, lbl) => { navigator.clipboard.writeText(txt); showToast(`${lbl} copied`); };

    return (
        <div className="space-y-8 animate-fade-in">
            <div className="flex flex-col md:flex-row gap-4 items-center justify-between">
                <div className="flex-1 w-full max-w-lg relative">
                    <Search className="absolute left-3.5 top-1/2 -translate-y-1/2 text-zinc-500" size={18} />
                    <Input
                        type="text"
                        value={q}
                        onChange={e => setQ(e.target.value)}
                        placeholder="Search by company or name..."
                        className="pl-11 bg-zinc-900/50 border-white/10"
                    />
                </div>
                <Button onClick={() => setShowAdd(!showAdd)} className="w-full md:w-auto bg-gradient-to-r from-blue-600 to-indigo-600">
                    {showAdd ? <X size={16} className="mr-2" /> : <Plus size={16} className="mr-2" />}
                    {showAdd ? 'Cancel' : 'Add HR Contact'}
                </Button>
            </div>

            {showAdd && (
                <Card className="animate-fade-in-up bg-zinc-900/50 backdrop-blur-md">
                    <CardHeader>
                        <CardTitle className="text-white">New HR Contact</CardTitle>
                        <CardDescription>Add a recruiter manually or auto-scrape by company</CardDescription>
                    </CardHeader>
                    <CardContent className="space-y-6">
                        <div className="flex gap-4 p-4 rounded-xl bg-blue-500/10 border border-blue-500/20">
                            <Input
                                placeholder="Company Name to Scrape (e.g. Razorpay)"
                                value={scrapeCompany}
                                onChange={e => setScrapeCompany(e.target.value)}
                                className="bg-black/50 border-blue-500/30"
                            />
                            <Button onClick={runScraper} disabled={isScraping} className="bg-blue-600 hover:bg-blue-500 font-bold w-40">
                                {isScraping ? 'Scraping...' : 'Auto-Find HR'}
                            </Button>
                        </div>
                        <Separator className="opacity-20" />
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                            <Input placeholder="Full Name *" value={form.name} onChange={e => setForm({ ...form, name: e.target.value })} />
                            <Input placeholder="Company *" value={form.company} onChange={e => setForm({ ...form, company: e.target.value })} />
                            <Input placeholder="Designation" value={form.designation} onChange={e => setForm({ ...form, designation: e.target.value })} />
                            <Input placeholder="Email Address *" value={form.email} onChange={e => setForm({ ...form, email: e.target.value })} />
                            <Input placeholder="LinkedIn URL" value={form.linkedinUrl} onChange={e => setForm({ ...form, linkedinUrl: e.target.value })} />
                            <Input placeholder="Hiring for role..." value={form.roleHiring} onChange={e => setForm({ ...form, roleHiring: e.target.value })} />
                        </div>
                        <div className="mt-6 flex justify-end">
                            <Button onClick={saveHR} variant="apply">Save Recruiter</Button>
                        </div>
                    </CardContent>
                </Card>
            )}

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                {filtered.map((h, i) => (
                    <Card key={h.id} className="animate-fade-in-up hover:-translate-y-1 transition-all duration-300">
                        <CardHeader>
                            <div className="flex items-start gap-4">
                                <Avatar className="h-12 w-12 bg-gradient-to-br from-blue-600 to-purple-600 text-sm">
                                    {h.name.split(' ').map(n => n[0]).join('')}
                                </Avatar>
                                <div className="flex-1 min-w-0">
                                    <CardTitle className="text-base text-white flex items-center gap-2 truncate">
                                        {h.name}
                                        {h.isVerified && <Check size={12} className="text-blue-400 bg-blue-500/10 rounded-full p-0.5 shrink-0" />}
                                    </CardTitle>
                                    <CardDescription className="truncate text-zinc-500">{h.designation}</CardDescription>
                                    <div className="text-xs font-bold text-blue-400 mt-1">{h.company}</div>
                                </div>
                            </div>
                        </CardHeader>

                        <CardContent className="space-y-4">
                            {h.roleHiring && (
                                <div className="flex items-center gap-2.5 p-2.5 rounded-lg bg-blue-500/5 border border-blue-500/10">
                                    <Building2 size={14} className="text-blue-500 shrink-0" />
                                    <span className="text-xs text-blue-300 font-medium">Hiring: {h.roleHiring.replace('Hiring ', '')}</span>
                                </div>
                            )}

                            <div className="space-y-3">
                                <div className="flex items-center justify-between group/email">
                                    <div className="flex items-center gap-2 text-xs text-zinc-400 truncate">
                                        <Mail size={14} className="shrink-0" />
                                        <span className="truncate">{h.email}</span>
                                    </div>
                                    <Button variant="ghost" size="icon" className="h-7 w-7 opacity-0 group-hover/email:opacity-100 transition-opacity" onClick={() => copy(h.email, 'Email')}>
                                        <Copy size={12} />
                                    </Button>
                                </div>

                                <div className="flex items-center justify-between group/linkedin">
                                    <div className="flex items-center gap-2 text-xs text-zinc-400 truncate">
                                        <Linkedin size={14} className="shrink-0" />
                                        <span className="truncate">View Profile</span>
                                    </div>
                                    <Button variant="ghost" size="icon" className="h-7 w-7 opacity-0 group-hover/linkedin:opacity-100 transition-opacity" onClick={() => window.open(h.linkedinUrl, '_blank')}>
                                        <Plus size={12} className="rotate-45" />
                                    </Button>
                                </div>
                            </div>
                        </CardContent>

                        <Separator className="opacity-50" />

                        <CardContent className="pt-4 pb-4">
                            <div className="flex gap-2">
                                <Button variant="outline" size="sm" className="flex-1" onClick={() => window.location.href = `mailto:${h.email}?subject=Interested in ${h.roleHiring || 'Product'} Role`}>
                                    <Mail size={14} className="mr-2" />
                                    Email
                                </Button>
                                <Button variant="apply" size="sm" className="flex-1" onClick={() => window.open(h.linkedinUrl, '_blank')}>
                                    <Linkedin size={14} className="mr-2" />
                                    Connect
                                </Button>
                            </div>
                        </CardContent>
                    </Card>
                ))}
            </div>
        </div>
    );
}

import * as React from 'react';
import {
    Search, Bookmark, MapPin, Users, Clock, Shield, Flame, Zap,
    Sparkles, BarChart3, X, Eye, Building2, TrendingUp
} from 'lucide-react';
import {
    Button, Card, CardHeader, CardTitle, CardDescription, CardContent,
    Badge, Input, MatchScoreCircle
} from './ui';
import { MOCK_JOBS, ROLE_GROUPS, BLOCKED_KEYWORDS } from '../data/constants';
import { calcATSScore, detectRoleGroup } from '../lib/ats';
import { useDebounce } from '../hooks/useHooks';
import { cn } from '../lib/utils';

// ===== ATS ANALYSIS PANEL (SHADCN STYLE) =====
function ATSPanel({ job, onClose }) {
    // Use backend ATS calculation if available, fallback to client-side
    const analysis = job.atsReport ? {
        rawScore: job.atsScore,
        exactMatches: job.atsReport.matchedSkills || [],
        missingSkills: job.atsReport.missingSkills || [],
        recommendations: job.atsReport.recommendations || []
    } : calcATSScore(job.skills, job.title);

    return (
        <div className="mt-6 p-6 rounded-xl bg-zinc-950 border border-white/5 animate-fade-in-up">
            <div className="flex justify-between items-center mb-6">
                <h4 className="font-bold flex items-center gap-2 text-white">
                    <BarChart3 size={18} className="text-blue-500" /> ATS Match Analysis
                </h4>
                <Button variant="ghost" size="icon" onClick={onClose} className="h-8 w-8">
                    <X size={16} />
                </Button>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-6">
                <div className="flex flex-col items-center justify-center p-6 rounded-xl bg-white/5 border border-white/5">
                    <MatchScoreCircle score={analysis.rawScore} size="lg" />
                    <p className="mt-4 font-bold text-white">Match Score</p>
                </div>

                <div className="md:col-span-2 space-y-4">
                    <div className="space-y-2">
                        <p className="text-[10px] font-bold text-zinc-500 uppercase tracking-widest">Matched Skills</p>
                        <div className="flex flex-wrap gap-1.5">
                            {analysis.exactMatches.map(s => <Badge key={s} variant="verified">{s}</Badge>)}
                            {analysis.exactMatches.length === 0 && <span className="text-xs text-zinc-600">None</span>}
                        </div>
                    </div>

                    <div className="space-y-2">
                        <p className="text-[10px] font-bold text-zinc-500 uppercase tracking-widest">Missing / Area for Improvement</p>
                        <div className="flex flex-wrap gap-1.5">
                            {analysis.missingSkills.map(s => <Badge key={s} variant="destructive" className="bg-red-500/10 text-red-400 border-red-500/20">{s}</Badge>)}
                            {analysis.missingSkills.length === 0 && <span className="text-xs text-zinc-600">Perfect Match!</span>}
                        </div>
                    </div>
                </div>
            </div>

            <div className="p-4 rounded-lg bg-blue-500/5 border border-blue-500/10">
                <p className="text-xs font-bold text-blue-400 mb-2 flex items-center gap-2">
                    <Sparkles size={14} /> Recommended Action
                </p>
                <div className="text-xs text-zinc-400 leading-relaxed">
                    {analysis.recommendations && analysis.recommendations.length > 0 ? (
                        <ul className="list-disc pl-4 space-y-1">
                            {analysis.recommendations.map((rec, i) => <li key={i}>{rec}</li>)}
                        </ul>
                    ) : analysis.rawScore > 80 ? (
                        <p>Your profile is a strong match. We recommend applying immediately and reaching out to the hiring manager via LinkedIn.</p>
                    ) : (
                        <p>Consider highlighting your 'McKinsey Forward' achievements to compensate for missing technical skills.</p>
                    )}
                </div>
            </div>
        </div>
    );
}

// ===== JOB CARD (PREMIUM DARK MODE) =====
function JobCard({ job, isSaved, onToggleSave, index }) {
